let website_id = "";

const input = $input.first().json;
const editFields = $('👉 Set Your Website URL Here').first().json;

for (const item of input.items) {
  if (item.url === editFields.website) {
    website_id = item.id;
    break;
  }
}

return [
  {
    json: {
      website_id
    }
  }
];

const inputJson = $input.first().json;

const root = Array.isArray(inputJson) ? inputJson[0] : inputJson;

const itemsArr = root?.items;

if (!Array.isArray(itemsArr) || itemsArr.length === 0) {
  throw new Error('No items found at input.json[0].items (or input.json.items).');
}

const idx = Math.floor(Math.random() * itemsArr.length);
const picked = itemsArr[idx];

return [{ json: picked }];
